@use_kernel_forward_from_hub("RMSNorm")
class OpenAIPrivacyFilterRMSNorm(nn.Module):
    def __init__(self, hidden_size, eps: float = 1e-6) -> None:
        """
        OpenAIPrivacyFilterRMSNorm is equivalent to T5LayerNorm
        """
        super().__init__()
        self.weight = nn.Parameter(torch.ones(hidden_size))
        self.variance_epsilon = eps

    def forward(self, hidden_states) -> torch.Tensor:
        input_dtype = hidden_states.dtype
        hidden_states = hidden_states.to(torch.float32)
        variance = hidden_states.pow(2).mean(-1, keepdim=True)
        hidden_states = hidden_states * torch.rsqrt(variance + self.variance_epsilon)
        return (self.weight * hidden_states).to(input_dtype)  # main diff with Llama

    def extra_repr(self):
        return f"{tuple(self.weight.shape)}, eps={self.variance_epsilon}"


class OpenAIPrivacyFilterRotaryEmbedding(nn.Module):
    inv_freq: torch.Tensor  # fix linting for `register_buffer`

    def __init__(self, config: OpenAIPrivacyFilterConfig, device=None):
        super().__init__()
        self.max_seq_len_cached = config.max_position_embeddings
        self.original_max_seq_len = config.max_position_embeddings

        self.config = config

        self.rope_type = self.config.rope_parameters["rope_type"]
        rope_init_fn: Callable = self.compute_default_rope_parameters
        if self.rope_type != "default":
            rope_init_fn = ROPE_INIT_FUNCTIONS[self.rope_type]
        inv_freq, self.attention_scaling = rope_init_fn(self.config, device)

        self.register_buffer("inv_freq", inv_freq, persistent=False)
        self.register_buffer("original_inv_freq", inv_freq.clone(), persistent=False)

    @staticmethod
    def compute_default_rope_parameters(
        config: OpenAIPrivacyFilterConfig | None = None,
        device: Optional["torch.device"] = None,
        seq_len: int | None = None,
    ) -> tuple["torch.Tensor", float]:
        """
        Computes the inverse frequencies according to the original RoPE implementation
        Args:
            config ([`~transformers.PreTrainedConfig`]):
                The model configuration.
            device (`torch.device`):
                The device to use for initialization of the inverse frequencies.
            seq_len (`int`, *optional*):
                The current sequence length. Unused for this type of RoPE.
        Returns:
            Tuple of (`torch.Tensor`, `float`), containing the inverse frequencies for the RoPE embeddings and the
            post-processing scaling factor applied to the computed cos/sin (unused in this type of RoPE).
        """
        base = config.rope_parameters["rope_theta"]
        dim = getattr(config, "head_dim", None) or config.hidden_size // config.num_attention_heads

        attention_factor = 1.0  # Unused in this type of RoPE

        # Compute the inverse frequencies
        inv_freq = 1.0 / (
            base ** (torch.arange(0, dim, 2, dtype=torch.int64).to(device=device, dtype=torch.float) / dim)
        )
        return inv_freq, attention_factor

    @torch.no_grad()
    @dynamic_rope_update  # power user: used with advanced RoPE types (e.g. dynamic rope)
    def forward(self, x, position_ids):
        inv_freq_expanded = self.inv_freq[None, :, None].float().expand(position_ids.shape[0], -1, 1).to(x.device)
        position_ids_expanded = position_ids[:, None, :].float()

        device_type = x.device.type if isinstance(x.device.type, str) and x.device.type != "mps" else "cpu"
        with maybe_autocast(device_type=device_type, enabled=False):  # Force float32
            freqs = (inv_freq_expanded.float() @ position_ids_expanded.float()).transpose(1, 2)
            emb = freqs
            cos = emb.cos() * self.attention_scaling
            sin = emb.sin() * self.attention_scaling

        return cos.to(x.dtype), sin.to(x.dtype)


@use_kernel_func_from_hub("rotary_pos_emb")
def apply_rotary_pos_emb(q, k, cos, sin, position_ids=None, unsqueeze_dim=1):
    cos = cos.unsqueeze(unsqueeze_dim)
    sin = sin.unsqueeze(unsqueeze_dim)
    q_embed = _apply_rotary_emb(q, cos, sin)
    k_embed = _apply_rotary_emb(k, cos, sin)
    return q_embed, k_embed


def _apply_rotary_emb(
    x: torch.Tensor,
    cos: torch.Tensor,
    sin: torch.Tensor,
) -> torch.Tensor:
    # Interleaving layout instead of concatenated
    first_half, second_half = x[..., ::2], x[..., 1::2]
    first_ = first_half * cos - second_half * sin
    second_ = second_half * cos + first_half * sin
    return torch.stack((first_, second_), dim=-1).flatten(-2)


def eager_attention_forward(
    module: nn.Module,
    query: torch.Tensor,
    key: torch.Tensor,
    value: torch.Tensor,
    attention_mask: torch.Tensor | None,
    scaling: float,
    dropout: float | int = 0.0,
    sliding_window: int | None = None,
    **kwargs,
):
    """Banded sliding-window attention with learnable sinks.

    Memory is O(N*W) in the token dimension rather than O(N*N): keys and values
    are extracted with `F.pad` + `Tensor.unfold` into per-query windows of width
    `sliding_window`, and scores are computed only inside the band. This matches
    the production attention path in OpenAI's `privacy-filter` reference
    implementation (Apache-2.0; see `opf/_model/model.py::sdpa`), the bidirectional
    branch at lines ~431-473.

    Notes on parity with the previous quadratic implementation:
      * Sinks: HF's checkpoint converter pre-multiplies sinks by `log(2)` at load
        time (see `convert_openai_privacy_filter_weights_to_hf.py`), so
        `module.sinks` is already in natural-log space. We concatenate them as a
        single extra column to scores before softmax and drop the column after,
        matching the previous behaviour bit-for-bit.
      * Sliding window: the caller (`OpenAIPrivacyFilterAttention`) passes
        `sliding_window = config.sliding_window + 1`. HF's convention is that
        FA receives `window_size = (sliding_window - 1, sliding_window - 1)`,
        i.e. `sliding_window - 1` tokens on each side, for a total bidirectional
        band of `2*(sliding_window - 1) + 1` tokens (including self). The eager
        mask in `sliding_window_bidirectional_overlay` matches: it attends to
        keys with `abs(q - kv) <= config.sliding_window`. We use the same
        `L = R = sliding_window - 1` half-width here for exact parity.
      * Padding: when an additive band+padding mask is supplied, per-key
        validity is recovered from the mask's diagonal (the diagonal lies inside
        the band for any bidi-SWA mask, so a non-`-inf` value implies the key is
        not padded). This is O(B*N) and never materialises the full N*N tensor.
      * `attn_weights`: the banded path does not materialise the full N*N
        attention matrix, so `attn_weights` is returned as `None`. Models that
        require `output_attentions=True` against this kernel will not receive
        per-pair weights from eager; use `attn_implementation="flash_attention_2"`
        (which never exposed weights either) or fall back via an upstream issue
        if a banded-form attention output is needed.
    """
    bsz, n_heads, n_tokens, head_dim = query.shape
    n_kv = key.shape[1]
    q_mult = n_heads // n_kv

    # HF convention: `sliding_window` arrives as `config.sliding_window + 1`,
    # producing `L = R = sliding_window - 1` per side and a total band of
    # `2*(sliding_window - 1) + 1`. Clamp the half-width by `n_tokens - 1` so a
    # sequence shorter than the band degenerates to full attention.
    if sliding_window is None or int(sliding_window) <= 0:
        half = max(0, n_tokens - 1)
    else:
        half = min(int(sliding_window) - 1, n_tokens - 1)
    left_ctx = right_ctx = half
    window = left_ctx + right_ctx + 1

    # Reshape into [B, N, KV, Q, D] / [B, N, KV, D] for cheap windowed einsum.
    q5 = query.permute(0, 2, 1, 3).reshape(bsz, n_tokens, n_kv, q_mult, head_dim)
    k4 = key.permute(0, 2, 1, 3)
    v4 = value.permute(0, 2, 1, 3)

    # Pad K/V along the token dim then sliding-window unfold to get per-query bands.
    # F.pad's pad-spec is last-dim-first; for a [B, N, KV, D] tensor padding dim 1
    # corresponds to the third pair of (left, right) entries.
    kp = F.pad(k4, (0, 0, 0, 0, left_ctx, right_ctx))
    vp = F.pad(v4, (0, 0, 0, 0, left_ctx, right_ctx))
    kwin = kp.unfold(1, window, 1).permute(0, 1, 4, 2, 3)  # [B, N, W, KV, D]
    vwin = vp.unfold(1, window, 1).permute(0, 1, 4, 2, 3)

    # Scores: einsum is O(N*W*KV*Q*D) memory and FLOPs, never N*N.
    scores = torch.einsum("bthqd,btwhd->bthqw", q5, kwin) * scaling

    # Boundary validity: positions that fall outside [0, N) due to the F.pad above.
    idx = torch.arange(window, device=query.device) - left_ctx
    pos = torch.arange(n_tokens, device=query.device)[:, None] + idx[None, :]  # [N, W]
    valid = (pos >= 0) & (pos < n_tokens)
    valid_b = valid[None, :, None, None, :]  # broadcast over [B, KV, Q]

    if attention_mask is not None:
        # Recover the per-key padding mask from the 4D additive mask's diagonal.
        # For bidi-SWA the diagonal is always in-band, so `mask[b, h, j, j]` is 0
        # for a valid token and -inf for a padded one.
        diag_mask = attention_mask.diagonal(dim1=-2, dim2=-1)  # [B, H_or_1, N]
        if diag_mask.dim() > 2:
            diag_mask = diag_mask[:, 0]  # any head will do; bidi-SWA mask is head-broadcastable
        key_valid_per_seq = diag_mask > torch.finfo(diag_mask.dtype).min  # [B, N]
        padded_valid = F.pad(key_valid_per_seq, (left_ctx, right_ctx), value=False)
        key_valid_win = padded_valid.unfold(-1, window, 1)  # [B, N, W]
        valid_full = valid_b & key_valid_win[:, :, None, None, :]
    else:
        valid_full = valid_b

    scores = scores.masked_fill(~valid_full, -float("inf"))

    # Sinks: HF stores them in natural-log space (see convert script).
    sinks = module.sinks.view(n_kv, q_mult)
    sink_scores = sinks[None, None, :, :, None].to(scores.dtype).expand(bsz, n_tokens, n_kv, q_mult, 1)
    scores = torch.cat([scores, sink_scores], dim=-1)

    # Subtract max for fp16/bf16 overflow safety, then softmax in fp32, then drop sink col.
    scores = scores - scores.max(dim=-1, keepdim=True).values
    probs = nn.functional.softmax(scores, dim=-1, dtype=torch.float32)
    probs = probs[..., :-1].to(value.dtype)
    probs = nn.functional.dropout(probs, p=dropout, training=module.training)

    attn = torch.einsum("bthqw,btwhd->bthqd", probs, vwin)  # [B, N, KV, Q, D]
    attn_output = attn.reshape(bsz, n_tokens, n_heads, head_dim)
    return attn_output, None


@use_kernelized_func(apply_rotary_pos_emb)
class OpenAIPrivacyFilterAttention(nn.Module):
    """Multi-headed attention from 'Attention Is All You Need' paper"""

    def __init__(self, config: OpenAIPrivacyFilterConfig):
        super().__init__()
        self.config = config
        self.head_dim = getattr(config, "head_dim", config.hidden_size // config.num_attention_heads)
        self.num_key_value_groups = config.num_attention_heads // config.num_key_value_heads
        self.scaling = config.head_dim**-0.25
        self.attention_dropout = config.attention_dropout
        self.is_causal = False
        self.q_proj = nn.Linear(
            config.hidden_size, config.num_attention_heads * self.head_dim, bias=config.attention_bias
        )
        self.k_proj = nn.Linear(
            config.hidden_size, config.num_key_value_heads * self.head_dim, bias=config.attention_bias
        )
        self.v_proj = nn.Linear(
            config.hidden_size, config.num_key_value_heads * self.head_dim, bias=config.attention_bias
        )
        self.o_proj = nn.Linear(
            config.num_attention_heads * self.head_dim, config.hidden_size, bias=config.attention_bias
        )
        self.sliding_window = config.sliding_window + 1  # Account for FA symmetry using -1
        self.sinks = nn.Parameter(torch.empty(config.num_attention_heads))

    def forward(
        self,
        hidden_states: torch.Tensor,
        position_embeddings: tuple[torch.Tensor, torch.Tensor],
        attention_mask: torch.Tensor | None = None,
        **kwargs: Unpack[TransformersKwargs],
    ) -> tuple[torch.Tensor, None]:
        input_shape = hidden_states.shape[:-1]
        hidden_shape = (*input_shape, -1, self.head_dim)

        query_states = self.q_proj(hidden_states).view(hidden_shape).transpose(1, 2)
        key_states = self.k_proj(hidden_states).view(hidden_shape).transpose(1, 2)
        value_states = self.v_proj(hidden_states).view(hidden_shape).transpose(1, 2)

        cos, sin = position_embeddings
        query_states, key_states = apply_rotary_pos_emb(query_states, key_states, cos, sin)

        # Unique: applying scale individually to each Q and K
        query_states = query_states * self.scaling
        key_states = key_states * self.scaling

        attention_interface: Callable = ALL_ATTENTION_FUNCTIONS.get_interface(
            self.config._attn_implementation, eager_attention_forward
        )

        attn_output, attn_weights = attention_interface(
            self,
            query_states,
            key_states,
            value_states,
            attention_mask,
            dropout=0.0 if not self.training else self.attention_dropout,
            scaling=1.0,  # scaling applied before
            sliding_window=self.sliding_window,
            s_aux=self.sinks,
            **kwargs,
        )

        attn_output = attn_output.reshape(*input_shape, -1).contiguous()
        attn_output = self.o_proj(attn_output)
        return attn_output, attn_weights


@use_experts_implementation(is_transposed=True, has_bias=True)
class OpenAIPrivacyFilterExperts(nn.Module):
    def __init__(self, config):
        super().__init__()
        self.intermediate_size = config.intermediate_size
        self.num_experts = config.num_local_experts
        self.hidden_size = config.hidden_size
        self.gate_up_proj = nn.Parameter(torch.empty(self.num_experts, self.hidden_size, 2 * self.intermediate_size))
        self.gate_up_proj_bias = nn.Parameter(torch.empty(self.num_experts, 2 * self.intermediate_size))
        self.down_proj = nn.Parameter(torch.empty((self.num_experts, self.intermediate_size, self.hidden_size)))
        self.down_proj_bias = nn.Parameter(torch.empty(self.num_experts, self.hidden_size))
        self.alpha = 1.702
        self.limit = 7.0

    def _apply_gate(self, gate_up: torch.Tensor) -> torch.Tensor:
        # Concatenated layout instead of interleaving
        gate, up = gate_up.chunk(2, dim=-1)
        gate = gate.clamp(min=None, max=self.limit)
        up = up.clamp(min=-self.limit, max=self.limit)
        glu = gate * torch.sigmoid(gate * self.alpha)
        gated_output = (up + 1) * glu
        return gated_output

    def forward(self, hidden_states: torch.Tensor, router_indices=None, routing_weights=None) -> torch.Tensor:
        original_dtype = hidden_states.dtype

        # Accumulate over fp32
        next_states = torch.zeros_like(hidden_states, dtype=torch.float32, device=hidden_states.device)
        with torch.no_grad():
            expert_mask = torch.nn.functional.one_hot(
                router_indices, num_classes=self.num_experts
            )  # masking is also a class
            expert_mask = expert_mask.permute(2, 1, 0)
            # we sum on the top_k and on the sequence length to get which experts
            # are hit this time around
            expert_hit = torch.greater(expert_mask.sum(dim=(-1, -2)), 0).nonzero()

        # Key change to original gpt oss is to stay in fp32 precision for all linear projections / muls
        for expert_idx in expert_hit:
            # expert_idx only have 1 element, so we can use scale for fast indexing
            expert_idx = expert_idx[0]
            # skip masking index
            if expert_idx == self.num_experts:
                continue
            top_k_pos, token_idx = torch.where(expert_mask[expert_idx])
            current_state = hidden_states[token_idx]
            gate_up = (
                current_state.float() @ self.gate_up_proj[expert_idx].float()
                + self.gate_up_proj_bias[expert_idx].float()
            )
            gated_output = self._apply_gate(gate_up).float()
            out = gated_output.float() @ self.down_proj[expert_idx].float() + self.down_proj_bias[expert_idx].float()
            weighted_output = out * routing_weights[token_idx, top_k_pos, None].float()
            next_states.index_add_(0, token_idx, weighted_output)

        return next_states.to(original_dtype)


class OpenAIPrivacyFilterTopKRouter(nn.Module):
    def __init__(self, config):
        super().__init__()
        self.top_k = config.num_experts_per_tok
        self.num_experts = config.num_local_experts
        self.hidden_dim = config.hidden_size
        self.weight = nn.Parameter(torch.zeros(self.num_experts, self.hidden_dim))
        self.bias = nn.Parameter(torch.zeros(self.num_experts))

    def forward(self, hidden_states):
        # Force fp32
        router_logits = F.linear(
            hidden_states.float(), self.weight.float(), self.bias.float()
        )  # (num_tokens, num_experts)
        router_top_value, router_indices = torch.topk(router_logits, self.top_k, dim=-1)  # (num_tokens, top_k)
        router_scores = torch.nn.functional.softmax(router_top_value, dim=1, dtype=router_top_value.dtype)
        # Additional scaling
        router_scores = router_scores / self.top_k
        return router_logits, router_scores, router_indices


class OpenAIPrivacyFilterMLP(nn.Module):
    """Similar to GPT Oss but with FP32 focus + added experts scaling"""

    def __init__(self, config):
        super().__init__()
        self.router = OpenAIPrivacyFilterTopKRouter(config)
        self.num_experts = config.num_experts_per_tok
        self.experts = OpenAIPrivacyFilterExperts(config)

    def forward(self, hidden_states):
        batch_size, sequence_length, hidden_dim = hidden_states.shape
        hidden_states = hidden_states.reshape(-1, hidden_dim)
        _, router_scores, router_indices = self.router(hidden_states)
        hidden_states = self.experts(hidden_states, router_indices, router_scores)
        # Additional scaling
        hidden_states = hidden_states * self.num_experts
        hidden_states = hidden_states.reshape(batch_size, sequence_length, hidden_dim)
        return hidden_states, router_scores


class OpenAIPrivacyFilterEncoderLayer(GradientCheckpointingLayer):
    def __init__(self, config: OpenAIPrivacyFilterConfig):
        super().__init__()
        self.hidden_size = config.hidden_size
        self.self_attn = OpenAIPrivacyFilterAttention(config)
        self.mlp = OpenAIPrivacyFilterMLP(config)
        self.input_layernorm = OpenAIPrivacyFilterRMSNorm(config.hidden_size, eps=config.rms_norm_eps)
        self.post_attention_layernorm = OpenAIPrivacyFilterRMSNorm(config.hidden_size, eps=config.rms_norm_eps)

    def forward(
        self,
        hidden_states: torch.Tensor,
        attention_mask: torch.Tensor | None = None,
        position_embeddings: tuple[torch.Tensor, torch.Tensor] | None = None,
        **kwargs: Unpack[TransformersKwargs],
    ) -> torch.Tensor:
        residual = hidden_states
        hidden_states = self.input_layernorm(hidden_states)
        # Self Attention
        hidden_states, _ = self.self_attn(
            hidden_states=hidden_states,
            position_embeddings=position_embeddings,
            attention_mask=attention_mask,
            **kwargs,
        )
        hidden_states = residual + hidden_states

        # Fully Connected
        residual = hidden_states
        hidden_states = self.post_attention_layernorm(hidden_states)
        hidden_states, _ = self.mlp(hidden_states)
        hidden_states = residual + hidden_states

        return hidden_states


@auto_docstring
class OpenAIPrivacyFilterPreTrainedModel(PreTrainedModel):
    config: OpenAIPrivacyFilterConfig
    base_model_prefix = "model"
    supports_gradient_checkpointing = True
    _no_split_modules = ["OpenAIPrivacyFilterEncoderLayer"]
    _skip_keys_device_placement = None  # No cache
    _supports_flash_attn = True
    _supports_sdpa = False
    _supports_flex_attn = True

    _can_compile_fullgraph = True
    _supports_attention_backend = True

    _can_record_outputs = {
        "router_logits": OutputRecorder(OpenAIPrivacyFilterTopKRouter, index=0),
        "hidden_states": OpenAIPrivacyFilterEncoderLayer,
        "attentions": OpenAIPrivacyFilterAttention,
    }
    _keep_in_fp32_modules = []
    _compatible_flash_implementations = ["kernels-community/vllm-flash-attn3", "flash_attention_4"]
    _keep_in_fp32_modules_strict = ["sinks"]

    @torch.no_grad()
    def _init_weights(self, module):
        super()._init_weights(module)
        std = self.config.initializer_range
        if isinstance(module, OpenAIPrivacyFilterExperts):
            init.normal_(module.gate_up_proj, mean=0.0, std=std)
            init.zeros_(module.gate_up_proj_bias)
            init.normal_(module.down_proj, mean=0.0, std=std)
            init.zeros_(module.down_proj_bias)
        elif isinstance(module, OpenAIPrivacyFilterAttention):
            init.normal_(module.sinks, mean=0.0, std=std)
        elif isinstance(module, OpenAIPrivacyFilterTopKRouter):
            init.normal_(module.weight, mean=0.0, std=std)
            init.normal_(module.bias, mean=0.0, std=std)

    def get_correct_experts_implementation(self, requested_experts: str | None) -> str:
        """The model is very sensitive to accumulation orders, hence we default to `eager` instead"""
        requested_experts = "eager" if requested_experts is None else requested_experts
        return super().get_correct_experts_implementation(requested_experts)


@auto_docstring
class OpenAIPrivacyFilterModel(OpenAIPrivacyFilterPreTrainedModel):
    def __init__(self, config: OpenAIPrivacyFilterConfig):
        super().__init__(config)
        self.padding_idx = config.pad_token_id
        self.vocab_size = config.vocab_size

        self.embed_tokens = nn.Embedding(config.vocab_size, config.hidden_size, self.padding_idx)
        self.layers = nn.ModuleList([OpenAIPrivacyFilterEncoderLayer(config) for _ in range(config.num_hidden_layers)])
        self.norm = OpenAIPrivacyFilterRMSNorm(config.hidden_size, eps=config.rms_norm_eps)
        self.rotary_emb = OpenAIPrivacyFilterRotaryEmbedding(config=config)
        self.gradient_checkpointing = False

        # Initialize weights and apply final processing
        self.post_init()

    @merge_with_config_defaults
    @capture_outputs
    @auto_docstring
    def forward(
        self,
        input_ids: torch.LongTensor | None = None,
        attention_mask: torch.Tensor | None = None,
        position_ids: torch.LongTensor | None = None,
        inputs_embeds: torch.FloatTensor | None = None,
        **kwargs: Unpack[TransformersKwargs],
    ) -> BaseModelOutput:
        if (input_ids is None) ^ (inputs_embeds is not None):
            raise ValueError("You must specify exactly one of input_ids or inputs_embeds")

        if inputs_embeds is None:
            inputs_embeds = self.embed_tokens(input_ids)
        hidden_states = inputs_embeds

        if position_ids is None:
            position_ids = torch.arange(inputs_embeds.shape[1], device=inputs_embeds.device)
            position_ids = position_ids.unsqueeze(0)
        position_embeddings = self.rotary_emb(hidden_states, position_ids)

        attention_mask = create_bidirectional_sliding_window_mask(
            config=self.config,
            inputs_embeds=hidden_states,
            attention_mask=attention_mask,
        )

        for encoder_layer in self.layers:
            hidden_states = encoder_layer(
                hidden_states,
                position_embeddings=position_embeddings,
                attention_mask=attention_mask,
                position_ids=position_ids,
                **kwargs,
            )

        hidden_states = self.norm(hidden_states)

        return BaseModelOutput(last_hidden_state=hidden_states)


